import{_ as a,o as r,c as t,a4 as s}from"./chunks/framework.Bv6IB9yN.js";const u=JSON.parse('{"title":"About agreements","description":"This page gives on overview of agreements in HUNT Cloud.","frontmatter":{"title":"About agreements","category":"HUNT Cloud","permalink":"/administer-science/start-here/agreements","outline":0,"description":"This page gives on overview of agreements in HUNT Cloud."},"headers":[],"relativePath":"administer-science/start-here/agreements.md","filePath":"administer-science/start-here/agreements.md"}'),o={name:"administer-science/start-here/agreements.md"};function n(i,e,d,l,c,m){return r(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="about-agreements" tabindex="-1">About agreements <a class="header-anchor" href="#about-agreements" aria-label="Permalink to &quot;About agreements&quot;">​</a></h1><p><strong>Since you work with sensitive data, documentation and agreements quickly becomes an essential part of a successful research environments. This page contains a quick overview of the most commonly used agreements in HUNT Cloud</strong></p><nav class="table-of-contents"><ul><li><a href="#lab-order">Lab order</a></li><li><a href="#user-agreement">User agreement</a></li><li><a href="#transfer-orders">Transfer orders</a></li><li><a href="#data-space-orders">Data space orders</a></li><li><a href="#organizational-agreements">Organizational agreements</a></li><li><a href="#read-more">Read more</a></li></ul></nav><h3 id="lab-order" tabindex="-1">Lab order <a class="header-anchor" href="#lab-order" aria-label="Permalink to &quot;Lab order&quot;">​</a></h3><p>This is the order that opens a new lab in HUNT Cloud. The order specify your lab name, the organization where the lab belongs, and two key roles in the day-to-day management of your lab (see below):</p><ul><li>Lab leader: This is the individual that is responsible for your activities inside your lab, typically the project leader or senior investigator in your lab team.</li><li>Lab coordinator: You have the option to add an additional individual that may coordinate day-to-day management, such as adding or removing users, upgrade or downgrade compute and storage resources and similar.</li></ul><p>Lab orders are co-signed by your Deputy head of department or Head of your research group.</p><h3 id="user-agreement" tabindex="-1">User agreement <a class="header-anchor" href="#user-agreement" aria-label="Permalink to &quot;User agreement&quot;">​</a></h3><p>This is the agreement that must be signed by every individual member of your lab team. The agreement states acceptable use policies for HUNT Cloud, and act as documentation of the users that are authorized access to the lab. User agreements are signed by the lab leader or the lab coordinator.</p><h3 id="transfer-orders" tabindex="-1">Transfer orders <a class="header-anchor" href="#transfer-orders" aria-label="Permalink to &quot;Transfer orders&quot;">​</a></h3><p>Data transfers between labs inside HUNT Cloud are documented in individual transfer agreements. Data transfers in and out of HUNT Cloud (external transfers) are also documented in similar agreements. Also, data network opening can also be ordered given that the lab leader hold permits for such transfers.</p><h3 id="data-space-orders" tabindex="-1">Data space orders <a class="header-anchor" href="#data-space-orders" aria-label="Permalink to &quot;Data space orders&quot;">​</a></h3><p>Data spaces is a way to effectively manage multiple labs in HUNT Cloud. You can add administrators that are authorized to manage activities across labs, including getting resource reports and financial reporting.</p><h3 id="organizational-agreements" tabindex="-1">Organizational agreements <a class="header-anchor" href="#organizational-agreements" aria-label="Permalink to &quot;Organizational agreements&quot;">​</a></h3><p>Lab agreements require that your host organization holds a data processing and services agreement with HUNT Cloud. These are typically signed by university departments or hospital clinic levels. If you organization lack such agreements, we will actively help you acquire relevant assessments and signatures.</p><h3 id="read-more" tabindex="-1">Read more <a class="header-anchor" href="#read-more" aria-label="Permalink to &quot;Read more&quot;">​</a></h3><ul><li><a href="/administer-science/agreements/">Agreement page</a></li></ul>',17)])])}const g=a(o,[["render",n]]);export{u as __pageData,g as default};
